// Validate email from form
const body = $json.body || $json;
const email = (body.email || '').trim().toLowerCase();
if (!email || !email.includes('@')) {
  throw new Error('Invalid or missing email');
}
return { json: { email, firstName: body.firstName || '', lastName: body.lastName || '', company: body.company || '', source: body.source || 'web-form' } };

// Merge Lusha + fallback data, preferring Lusha where available
const form = $('Validate Email').first().json;
const lusha = $('Enrich with Lusha').first().json;
const fb = $json;

return { json: {
  email: form.email,
  firstName: form.firstName || lusha.firstName || fb.firstName || '',
  lastName: form.lastName || lusha.lastName || fb.lastName || '',
  company: form.company || lusha.companyName || fb.company || '',
  jobTitle: lusha.jobTitle || fb.jobTitle || '',
  seniority: lusha.seniority || fb.seniority || '',
  phone: lusha.primaryPhone || fb.phone || '',
  verifiedEmail: lusha.primaryEmail || fb.email || '',
  companyDomain: lusha.companyDomain || fb.domain || '',
  companySize: lusha.companySize || fb.companySize || '',
  industry: lusha.companyMainIndustry || fb.industry || '',
  revenueRange: lusha.revenueRange || '',
  linkedinUrl: lusha.linkedinProfile || '',
  enrichmentSource: lusha.primaryEmail ? 'lusha+fallback' : 'fallback',
  source: form.source,
  enrichedAt: new Date().toISOString()
} };

